{"nbformat":4,"nbformat_minor":0,"metadata":{"colab":{"provenance":[],"authorship_tag":"ABX9TyP34AAPkaNqyxAe8JPCorwn"},"kernelspec":{"name":"python3","display_name":"Python 3"},"language_info":{"name":"python"}},"cells":[{"cell_type":"code","execution_count":1,"metadata":{"id":"Jsgk5vKWyWL1","executionInfo":{"status":"ok","timestamp":1772391877632,"user_tz":-180,"elapsed":3429,"user":{"displayName":"Sema Hacıbekiroğlu","userId":"10657115845303637897"}}},"outputs":[],"source":["from sklearn.ensemble import RandomForestClassifier\n","from sklearn.metrics import accuracy_score, precision_score, recall_score, f1_score\n","\n","class RandomForestModel:\n","    def __init__(self):\n","        self.model = RandomForestClassifier(\n","            n_estimators=200,\n","            max_depth=8,\n","            random_state=42\n","        )\n","\n","    def train(self, X_train, y_train):\n","        self.model.fit(X_train, y_train)\n","\n","    def evaluate(self, X_test, y_test):\n","        y_pred = self.model.predict(X_test)\n","        return {\n","            \"Accuracy\": accuracy_score(y_test, y_pred),\n","            \"Precision\": precision_score(y_test, y_pred),\n","            \"Recall\": recall_score(y_test, y_pred),\n","            \"F1 Score\": f1_score(y_test, y_pred)\n","        }"]}]}